INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("リンド", 127702, 2, "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", 10005, -470.0, "2023/09/15 15:00:00", "2023/12/22 14:59:59", 2002, 0.0, 1, 2, 2, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("リンド", 127702, 2, "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", 10006, -470.0, "2023/09/15 15:00:00", "2023/12/22 14:59:59", 2002, 0.0, 2, 2, 2, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ヴルム", 127802, 2, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", 10007, -470.0, "2023/09/15 15:00:00", "2023/12/22 14:59:59", 2002, 0.0, 1, 1, 1, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ヴルム", 127802, 2, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", 10008, -470.0, "2023/09/15 15:00:00", "2023/12/22 14:59:59", 2002, 6.5, 2, 2, 1, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("アネモネ", 129602, 3, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", 10009, -470.0, "2023/12/15 15:00:00", "2024/03/22 14:59:59", 2002, 0.0, 1, 2, 1, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("アネモネ", 129602, 3, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", 10010, -470.0, "2023/12/15 15:00:00", "2024/03/22 14:59:59", 2002, 0.0, 2, 2, 1, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ネフィ=ネラ", 129701, 3, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", 10011, -470.0, "2023/12/15 15:00:00", "2024/03/22 14:59:59", 2002, 0.0, 1, 1, 1, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ネフィ=ネラ", 129701, 3, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", 10012, -470.0, "2023/12/15 15:00:00", "2024/03/22 14:59:59", 2002, 6.2, 2, 2, 1, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("カノン", 130301, 4, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", 10013, -470.0, "2024/03/15 15:00:00", "2024/06/22 14:59:59", 2002, 3.1, 1, 3, 5, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("カノン", 130301, 4, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", 10014, -470.0, "2024/03/15 15:00:00", "2024/06/22 14:59:59", 2002, 6.15, 2, 3, 2, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ナーナ", 130401, 4, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", 10015, -470.0, "2024/03/15 15:00:00", "2024/06/22 14:59:59", 2002, 0.0, 1, 2, 2, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ナーナ", 130401, 4, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", 10016, -470.0, "2024/03/15 15:00:00", "2024/06/22 14:59:59", 2002, 3.35, 2, 2, 1, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ホウオウ", 130502, 5, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", 10017, -470.0, "2024/06/15 15:00:00", "2024/09/22 14:59:59", 2002, 0.0, 1, 1, 1, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ホウオウ", 130502, 5, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", 10018, -470.0, "2024/06/15 15:00:00", "2024/09/22 14:59:59", 2002, 3.18, 2, 2, 1, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ホウオウ", 130503, 5, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", 10019, -470.0, "2024/06/15 15:00:00", "2024/09/22 14:59:59", 2002, 0.0, 3, 4, 4, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ネア", 123301, 5, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", 10020, -470.0, "2024/06/15 15:00:00", "2024/09/22 14:59:59", 2002, 4.9, 1, 1, 2, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ネア", 123301, 5, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", 10021, -470.0, "2024/06/15 15:00:00", "2024/09/22 14:59:59", 2002, 4.8, 2, 1, 2, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("カリザ", 133301, 6, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", 10022, -470.0, "2024/09/15 15:00:00", "2024/12/22 14:59:59", 2002, 4.922, 1, 3, 1, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("カリザ", 133301, 6, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", 10023, -470.0, "2024/09/15 15:00:00", "2024/12/22 14:59:59", 2002, 9.638, 2, 3, 5, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ミーア", 133401, 6, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", 10024, -470.0, "2024/09/15 15:00:00", "2024/12/22 14:59:59", 2002, 2.88, 1, 1, 2, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ミーア", 133401, 6, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", 10025, -470.0, "2024/09/15 15:00:00", "2024/12/22 14:59:59", 2002, 4.818, 2, 5, 1, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("グレイス", 133002, 7, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", 10026, -470.0, "2024/12/15 15:00:00", "2025/03/22 14:59:59", 2002, 1.78, 1, 2, 1, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("グレイス", 133002, 7, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", 10027, -470.0, "2024/12/15 15:00:00", "2025/03/22 14:59:59", 2002, 6.15, 2, 1, 7, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ヴァイオレット", 133102, 7, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", 10028, -470.0, "2024/12/15 15:00:00", "2025/03/22 14:59:59", 2002, 4.28, 1, 6, 2, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ヴァイオレット", 133102, 7, "じめじめした商品は\nございませんので\n安心してお買い求め下さい", 10029, -470.0, "2024/12/15 15:00:00", "2025/03/22 14:59:59", 2002, 0.0, 2, 1, 1, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ルルィ", 136902, 8, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", 10030, -470.0, "2025/03/15 15:00:00", "2025/06/23 14:59:59", 2002, 5.53, 1, 2, 1, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ルルィ", 136902, 8, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", 10031, -470.0, "2025/03/15 15:00:00", "2025/06/23 14:59:59", 2002, 6.05, 2, 9, 7, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("デュラン", 137001, 8, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", 10032, -470.0, "2025/03/15 15:00:00", "2025/06/23 14:59:59", 2002, 0.0, 1, 2, 1, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("デュラン", 137001, 8, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", 10033, -470.0, "2025/03/15 15:00:00", "2025/06/23 14:59:59", 2002, 0.0, 2, 2, 1, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("サツキ", 135902, 9, "おう\n好きなもん持ってきな", 10034, -470.0, "2025/06/16 15:00:00", "2025/09/23 14:59:59", 2002, 0.0, 1, 2, 2, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("サツキ", 135902, 9, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", 10035, -470.0, "2025/06/16 15:00:00", "2025/09/23 14:59:59", 2002, 4.935, 2, 1, 6, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ユキノ", 135802, 9, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", 10036, -470.0, "2025/06/16 15:00:00", "2025/09/23 14:59:59", 2002, 7.441, 1, 2, 5, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ユキノ", 135802, 9, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", 10037, -470.0, "2025/06/16 15:00:00", "2025/09/23 14:59:59", 2002, 0.0, 2, 7, 7, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("クルル", 130901, 10, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", 10038, -470.0, "2025/09/16 15:00:00", "2025/12/22 14:59:59", 2002, 2.295, 1, 2, 2, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("クルル", 130901, 10, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", 10039, -470.0, "2025/09/16 15:00:00", "2025/12/22 14:59:59", 2002, 6.281, 2, 1, 6, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ヴォルガーノ", 137701, 10, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", 10040, -470.0, "2025/09/16 15:00:00", "2025/12/22 14:59:59", 2002, 5.549, 1, 2, 1, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ヴォルガーノ", 137701, 10, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", 10041, -470.0, "2025/09/16 15:00:00", "2025/12/22 14:59:59", 2002, 2.64, 2, 3, 6, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ライラエル", 132801, 11, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", 10042, -470.0, "2025/12/15 15:00:00", "2026/03/23 11:59:59", 2002, 7.642, 1, 7, 4, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ライラエル", 132802, 11, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", 10043, -470.0, "2025/12/15 15:00:00", "2026/03/23 11:59:59", 2002, 0.0, 2, 1, 1, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("クローチェ", 134502, 11, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", 10044, -470.0, "2025/12/15 15:00:00", "2026/03/23 11:59:59", 2002, 0.0, 1, 1, 1, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("クローチェ", 134501, 11, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", 10045, -470.0, "2025/12/15 15:00:00", "2026/03/23 11:59:59", 2002, 3.72, 2, 2, 1, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ネフィ＝ネラ", 138201, 12, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", 10046, -470.0, "2026/03/16 12:00:00", "2026/06/22 11:59:59", 2002, 4.991, 1, 2, 1, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ネフィ＝ネラ", 138201, 12, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", 10047, -470.0, "2026/03/16 12:00:00", "2026/06/22 11:59:59", 2002, 3.877, 2, 1, 4, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("アラクネ", 136001, 12, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", 10048, -470.0, "2026/03/16 12:00:00", "2026/06/22 11:59:59", 2002, 1.71, 1, 4, 6, 0.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("アラクネ", 136001, 12, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", 10049, -470.0, "2026/03/16 12:00:00", "2026/06/22 11:59:59", 2002, 5.32, 2, 5, 2, 0.0);
